        ```code
        import java.io.File;
import java.io.FileNotFoundException;
import java.io.PrintWriter;
import java.util.LinkedList;
import java.util.Scanner;

class Point {
	enum Direction {
		NORTH, EAST, SOUTH, WEST, ANY
	}
	int x, y, cost;
	Direction direction;
	public Point(int _x, int _y, int _cost, Direction _direction) {
		x = _x;
		y = _y;
		cost = _cost;
		direction = _direction;
	}
}

public class Beamdrone {
	public static final String input = "beamdrone.in";
	public static final String output = "beamdrone.out";
	public static int INF = (int) 1e9;

	public static boolean checkNodeValid(Point point, int[][] grid, int n, int m) {
		if (point.direction == Point.Direction.NORTH && point.x + 1 < n) {
			if (grid[point.x][point.y] < grid[point.x + 1][point.y]) {
				return false;
			}
		}
		if (point.direction == Point.Direction.SOUTH && point.x - 1 >= 0) {
			if (grid[point.x][point.y] < grid[point.x - 1][point.y]) {
				return false;
			}
		}
		if (point.direction == Point.Direction.WEST && point.y + 1 < m) {
			if (grid[point.x][point.y] < grid[point.x][point.y + 1]) {
				return false;
			}
		}
		if (point.direction == Point.Direction.EAST && point.y - 1 >= 0) {
			if (grid[point.x][point.y] < grid[point.x][point.y - 1]) {
				return false;
			}
		}
		return true;
	}

	public static void main(String[] args) throws FileNotFoundException {
		Scanner sc = new Scanner(new File(input));
		int n = sc.nextInt();
		int m = sc.nextInt();
		int[][] grid = new int[n][m];
		int xi = sc.nextInt();
		int yi = sc.nextInt();
		int xf = sc.nextInt();
		int yf = sc.nextInt();
		for (int i = 0; i < n; i++) {
			String line = sc.next();
			for (int j = 0; j < m; j++) {
				if (line.charAt(j) == '.') {
					grid[i][j] = INF;
				} else {
					grid[i][j] = -1;
				}
			}
		}
		grid[xi][yi] = 0;
		LinkedList<Point> queue = new LinkedList<>();
		queue.addLast(new Point(xi, yi, 0, Point.Direction.ANY));
		while (!queue.isEmpty()) {
			Point curr = queue.removeFirst();
			if (curr.cost > grid[curr.x][curr.y]) {
				continue;
			}
			if (grid[curr.x][curr.y] > grid[xf][yf]) {
				continue;
			}
			if (curr.x - 1 >= 0 && grid[curr.x - 1][curr.y] != -1) {
				if ((curr.direction == Point.Direction.NORTH
						|| curr.direction == Point.Direction.ANY)
						&& grid[curr.x][curr.y] <= grid[curr.x - 1][curr.y]) {
					grid[curr.x - 1][curr.y] = grid[curr.x][curr.y];
					queue.addLast(new Point(curr.x - 1, curr.y, grid[curr.x][curr.y],
							Point.Direction.NORTH));
				} else if (grid[curr.x][curr.y] + 1 <= grid[curr.x - 1][curr.y]) {
					grid[curr.x - 1][curr.y] = grid[curr.x][curr.y] + 1;
					queue.addLast(new Point(curr.x - 1, curr.y, grid[curr.x][curr.y] + 1,
							Point.Direction.NORTH));
				}
			}
			if (curr.x + 1 < n && grid[curr.x + 1][curr.y] != -1) {
				if ((curr.direction == Point.Direction.SOUTH
						|| curr.direction == Point.Direction.ANY)
						&& grid[curr.x][curr.y] <= grid[curr.x + 1][curr.y]) {
					grid[curr.x + 1][curr.y] = grid[curr.x][curr.y];
					queue.addLast(new Point(curr.x + 1, curr.y, grid[curr.x][curr.y],
							Point.Direction.SOUTH));
				} else if (grid[curr.x][curr.y] + 1 <= grid[curr.x + 1][curr.y]) {
					grid[curr.x + 1][curr.y] = grid[curr.x][curr.y] + 1;
					queue.addLast(new Point(curr.x + 1, curr.y, grid[curr.x][curr.y] + 1,
							Point.Direction.SOUTH));
				}
			}
			if (curr.y - 1 >= 0 && grid[curr.x][curr.y - 1] != -1) {
				if ((curr.direction == Point.Direction.WEST
						|| curr.direction == Point.Direction.ANY)
						&& grid[curr.x][curr.y] <= grid[curr.x][curr.y - 1]) {
					grid[curr.x][curr.y - 1] = grid[curr.x][curr.y];
					queue.addLast(new Point(curr.x, curr.y - 1, grid[curr.x][curr.y],
							Point.Direction.WEST));
				} else if (grid[curr.x][curr.y] + 1 <= grid[curr.x][curr.y - 1]) {
					grid[curr.x][curr.y - 1] = grid[curr.x][curr.y] + 1;
					queue.addLast(new Point(curr.x, curr.y - 1, grid[curr.x][curr.y] + 1,
							Point.Direction.WEST));
				}
			}
			if (curr.y + 1 < m && grid[curr.x][curr.y + 1] != -1) {
				if ((curr.direction == Point.Direction.EAST
						|| curr.direction == Point.Direction.ANY)
						&& grid[curr.x][curr.y] <= grid[curr.x][curr.y + 1]) {
					grid[curr.x][curr.y + 1] = grid[curr.x][curr.y];
					queue.addLast(new Point(curr.x, curr.y + 1, grid[curr.x][curr.y],
							Point.Direction.EAST));
				} else if (grid[curr.x][curr.y] + 1 <= grid[curr.x][curr.y + 1]) {
					grid[curr.x][curr.y + 1] = grid[curr.x][curr.y] + 1;
					queue.addLast(new Point(curr.x, curr.y + 1, grid[curr.x][curr.y] + 1,
							Point.Direction.EAST));
				}
			}
		}
		PrintWriter pw = new PrintWriter(output);
		pw.printf("%d", grid[xf][yf]);
		pw.close();
	}
}

