			if (valleys.get(i) < valleys.get(i + 1)) {
				long dif = valleys.get(i + 1) - valleys.get(i);
				valleys.set(i + 1, valleys.get(i + 1) - dif);
				count += dif;
			}
		}

		/* check to see if sufixes respect rule, if not excavate and add
		 the difference to final count
		 */
		for (int i = n - 1; i > pos; i--) {
			if (valleys.get(i) < valleys.get(i - 1)) {
				long dif = valleys.get(i - 1) - valleys.get(i);
				valleys.set(i - 1, valleys.get(i - 1) - dif);
				count += dif;
			}
		}


		try (FileWriter fileWriter = new FileWriter("valley.out")) {
			try (BufferedWriter bufferedWriter = new BufferedWriter(fileWriter)) {
				bufferedWriter.write(String.valueOf(count));
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

	}
}
