#include <cstdint>
#include <fstream>
#include <vector>
#include <algorithm>

using namespace std;

int64_t SolveTask1(const vector<int>& a, const vector<int>& b) {
    vector<int> c(a);
    c.insert(c.end(), b.begin(), b.end());
    int n = a.size(), i;
    int64_t s = 0;
    sort(c.begin(), c.end(), greater<int>());
    for (i = 0; i < n; ++i)
        s += c.at(i);
    return s;
}

int64_t SolveTask2(const vector<int>& a, const vector<int>& b, int moves) {
    vector<int> da, nu;
    int n = a.size(), i;
    for (i = 0; i < n; ++i) {
        if (a.at(i) > b.at(i)) {
            da.push_back(a.at(i));
            nu.push_back(b.at(i));
        } else {
            da.push_back(b.at(i));
            nu.push_back(a.at(i));
        }
    }
    sort(da.begin(), da.end(), greater<int>());
    sort(nu.begin(), nu.end(), greater<int>());
    int64_t s = 0;

    for (i = 0; i < n; ++i)
        if (i < moves && da.at(n - 1 - i) < nu.at(i))
            s += nu.at(i);
        else
            s += da.at(n - 1 - i);

    return s;
}

vector<int> ReadVector(istream& is, int size) {
    vector<int> vec(size);
    for (auto& num : vec) {
        is >> num;
    }
    return vec;
}

int main() {
    ifstream fin("nostory.in");
    ofstream fout("nostory.out");

    int task;
    fin >> task;

    int n, moves;
    if (task == 1) {
        fin >> n;
    } else {
        fin >> n >> moves;
    }

    auto a = ReadVector(fin, n);
    auto b = ReadVector(fin, n);

    auto res = task == 1 ? SolveTask1(a, b) : SolveTask2(a, b, moves);
    fout << res << "\n";

    return 0;
}

