import java.util.HashMap;
import java.util.Map;
import java.util.StringTokenizer;

public class Nostory {
	public static void main(final String[] args) throws IOException {
		var scanner = new MyScanner(new FileReader("nostory.in"));

		var task = scanner.nextInt();
		var n = scanner.nextInt();
		var moves = task == 2 ? scanner.nextInt() : 0;

		var a = new long[n];
		for (var i = 0; i < n; i += 1) {
			a[i] = scanner.nextLong();
		}

		var b = new long[n];
		for (var i = 0; i < n; i += 1) {
			b[i] = scanner.nextLong();
		}

		try (var printer = new PrintStream("nostory.out")) {
			if (task == 1) {
				printer.println(solveTask1(a, b));
			} else {
				printer.println(solveTask2(a, b, moves));
			}
		}
	}

	private static long solveTask1(long[] a, long[] b) {
		ArrayList<Long> c = new ArrayList<Long>();

		// Add all values from a to an arbitrary array c
		for (long num : a) {
			c.add(num);
		}

		// Add all values from b to an arbitrary array c
		for (long num : b) {
			c.add(num);
		}

		// Sort the resulting c
		Collections.sort(c);

		// Get first n / 2 maximum values to result
		long sum = 0;
		for (int i = c.size() - 1; i >= c.size() / 2; i--) {
			sum += c.get(i);
		}

		return sum;
	}

	static HashMap<Long, Integer> createMap(long[] a, long[] b, int n) {
		// Add values to Hash Map so we have evidence of already used values
		HashMap<Long, Integer> visited = new HashMap<Long, Integer>();

		// Add to visited map with 1 as value(meaning visited) the bigger
		// element in pair (a[i], b[i])
		for (int i = 0; i < n; i++) {
			if (a[i] > b[i]) {
				visited.put(a[i], 1);
				visited.put(b[i], 0);
			} else {
				visited.put(b[i], 1);
				visited.put(a[i], 0);
			}
		}

		return visited;
	}

	static long computeResult(HashMap<Long, Integer> visited, int n, int moves, long[] combined) {
		// Initialise result and counter
		long sum = 0;
		long cnt = 0;

		// Start from the bigger values
		int iter = 2 * n - 1;

		// Add all visited values and non visited while we still have moves
		// If we reached target size in best solution we stop
		while (cnt < n) {
			Integer value = visited.get(combined[iter]);

			// If entry is visited we add it to result and increase counter
			if (value == 1) {
				sum += combined[iter];
				cnt++;
			} else {
				// If it is not visited but we can make a move to shift it into
				// a pair where it would be
				// taken in consideration we do that and decrease number of available moves
				if (moves > 0) {
					sum += combined[iter];
					moves--;
					cnt++;
				}
			}

			iter--;
		}

		return sum;
	}

	private static long solveTask2(long[] a, long[] b, int moves) {
		try {
			int n = a.length;

			// Create a combined array with all elements from a and b
			long[] combined = new long[2 * n];
			System.arraycopy(a, 0, combined, 0, n);
			System.arraycopy(b, 0, combined, n, n);

			// Sort the array so we take the bigger values
			Arrays.sort(combined);

			// Create the visited map
			HashMap<Long, Integer> visited = createMap(a, b, n);

			// Compute the answer
			return computeResult(visited, n, moves, combined);
		} catch (Exception e) {
			throw new RuntimeException(e);
		}
	}

