        import java.io.BufferedWriter;
import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import static java.lang.Integer.parseInt;
import java.util.*;

public class Fortificatii {
	public static final String INPUT_FILE = "fortificatii.in";
	public static final String OUTPUT_FILE = "fortificatii.out";
	public static final int INF = (int) 1e9;

	int n, m;
	long k;
	int source = 1;
	Set<Integer> hash_Set = new HashSet<>();

	ArrayList<Pair> adj[] = new ArrayList[(int)1e5 + 2];
	public class DijkstraResult {
		List<Long> d;
		DijkstraResult(List<Long> _d) {
			d = _d;
		}
	};

	public class Pair implements Comparable<Pair> {
		public int destination;
		public long cost;
		Pair(int _destination, long _cost) {
			destination = _destination;
			cost = _cost;
		}
		public int compareTo(Pair rhs) {
			if(cost > rhs.cost) return 1;
			else return -1;
		}
	}

	public void solve() {
		readInput();
		writeOutput(getResult());
	}

	private void writeOutput(Long result) {
		try {
			BufferedWriter bw = new BufferedWriter(new FileWriter(
					OUTPUT_FILE));

			StringBuilder sb = new StringBuilder();

			sb.append(result);
			sb.append('\n');

			bw.write(sb.toString());
			bw.close();
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	private void readInput() {
		try {
			Scanner sc = new Scanner(new File(INPUT_FILE));
			String string = sc.nextLine();
			String[] currencies = string.split(" ");

			n = parseInt(currencies[0]);
			m = parseInt(currencies[1]);
			k = parseInt(currencies[2]);

			for (int i = 1; i <= n; i++) {
				adj[i] = new ArrayList<>();
			}

			string = sc.nextLine();
			String [] barbars = string.split(" ");

			for(int i = 1; i <= parseInt(barbars[0]); i++)
				hash_Set.add(Integer.parseInt(barbars[i]));

			for(int i = 0; i < m; i++) {
				string = sc.nextLine();
				String [] nodes = string.split(" ");
				adj[parseInt(nodes[0])].add(new Pair(parseInt(nodes[1]), parseInt(nodes[2])));
				adj[parseInt(nodes[1])].add(new Pair(parseInt(nodes[0]), parseInt(nodes[2])));
			}
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	public static void main(String[] args) throws Exception{
		new Fortificatii().solve();
	}

	private Long getResult() {
		DijkstraResult dijkstraResult = dijkstra(source, n, adj);
		List<Long> routes = new ArrayList<>();
		for (Integer i : hash_Set)
			for (Pair pair : adj[i]) {
				if(hash_Set.contains(pair.destination) != true) {
					if (dijkstraResult.d.get(pair.destination) + pair.cost != 0 && dijkstraResult.d.get(pair.destination) != -1) {
						routes.add(dijkstraResult.d.get(pair.destination) + pair.cost);
					}
				}
			}

		Collections.sort(routes);
		int howMany = 1;

		for(int i = 0; i < routes.size(); i ++) {
			if (i + 1 != routes.size()) {
				if (k >= (routes.get(i + 1) - routes.get(i)) * howMany) {
					k = k - howMany * (routes.get(i + 1) - routes.get(i));
					howMany++;
				} else if (k == 0) {
					return routes.get(howMany - 1);
				}
				else {
					long dif = k / howMany;
					return dif + routes.get(howMany - 1);
				}
			} else {
				howMany = routes.size();
				long dif = k / howMany;
				return dif + routes.get(routes.size() - 1);
			}
		}
		return 1L;
	}

	private DijkstraResult dijkstra(int source, int nodes, ArrayList<Pair> adj[]) {
		List<Long> d = new ArrayList<>();

		for (int node = 0; node <= nodes; node++) {
			d.add(Long.MAX_VALUE / 2);
		}

		PriorityQueue<Pair> pq = new PriorityQueue<>();

		d.set(source, 0L);
		pq.add(new Pair(source, 0));

		while (!pq.isEmpty()) {
			long cost = pq.peek().cost;
			int node = pq.poll().destination;

			if (cost > d.get(node)) {
				continue;
			}

			for (var e : adj[node]) {
				if(hash_Set.contains(e.destination)) continue;

				int neigh = e.destination;
				long w = e.cost;

				if (d.get(node) + w < d.get(neigh)) {
					d.set(neigh, d.get(node) + w);
					pq.add(new Pair(neigh, d.get(neigh)));
				}
			}
		}

		for (int i = 1; i <= n; i++) {
			if (d.get(i) == Long.MAX_VALUE / 2) {
				d.set(i, -1L);
			}
		}


		return new DijkstraResult(d);
	}
}



