        import java.io.File;
import java.io.IOException;
import java.io.PrintWriter;
import java.nio.file.Paths;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collections;
import java.util.PriorityQueue;
import java.util.Scanner;

public class Fortificatii {
	static class Edge implements Comparable<Edge> {
		int node;
		long weight;

		public Edge(int node, long weight) {
			this.node = node;
			this.weight = weight;
		}

		@Override
		public int compareTo(Edge e) {
			return Long.compare(this.weight, e.weight);
		}

	}

	static int nrCities, nrRoutes, nrFort, nrBar;
	static ArrayList<Integer> barLocations = new ArrayList<>();
	static ArrayList<ArrayList<Edge>> adjList;
	static long[] distances;

	public static void dijkstra(int source) {
		distances = new long[nrCities + 1];
		Arrays.fill(distances, Integer.MIN_VALUE);

		PriorityQueue<Edge> pq = new PriorityQueue<>();

		distances[source] = 0;
		Edge edge = new Edge(source, 0);

		pq.add(edge);

		while (!pq.isEmpty()) {
			Edge currEdge = pq.poll();
			int node = currEdge.node;

			if (barLocations.contains(node)) {
				continue;
			}

			ArrayList<Edge> neighs = adjList.get(node);

			for (Edge edge1 : neighs) {
				if (distances[edge1.node] == Integer.MIN_VALUE
						|| currEdge.weight + edge1.weight < distances[edge1.node]) {
					distances[edge1.node] = currEdge.weight + edge1.weight;
					pq.add(new Edge(edge1.node, distances[edge1.node]));
				}
			}
		}
	}

	public static long getMinDist() {
		ArrayList<Long> allDistsances = new ArrayList<>();
		for (Integer barbar : barLocations) {
			// Aleg nodurile vecine barbarilor care nu sunt barbare si calculez
			// distanta pana la aceste asezari brbare prin nodurile adiacente. 
			for (Edge edge : adjList.get(barbar)) {
				if (!barLocations.contains(edge.node)
						&& distances[edge.node] != Integer.MIN_VALUE) {
					allDistsances.add(edge.weight + distances[edge.node]);
				}
			}
		}

		Collections.sort(allDistsances);

		int i;
		for (i = 1; i < allDistsances.size(); i++) {
			long dist = (allDistsances.get(i) - allDistsances.get(i - 1)) * i;
			if (nrFort - dist >= 0) {
				nrFort -= dist;
			} else {
				break;
			}
		}
		long result = allDistsances.get(i - 1) + nrFort / i;

		return result;
	}

	public static void main(String[] args) throws IOException {
		Scanner scanner =  new Scanner(Paths.get("fortificatii.in"));

		nrCities = scanner.nextInt();
		nrRoutes = scanner.nextInt();
		nrFort = scanner.nextInt();

		nrBar = scanner.nextInt();
		for (int i = 0; i < nrBar; i++) {
			int loc = scanner.nextInt();
			barLocations.add(loc);
		}

		adjList = new ArrayList<>(nrCities);
		for (int i = 0; i <= nrCities; i++) {
			adjList.add(new ArrayList<Edge>());
		}

		for (int i = 0; i < nrRoutes; i++) {
			int src = scanner.nextInt();
			int dst = scanner.nextInt();
			int weight = scanner.nextInt();
			Edge newEdge1 = new Edge(dst, weight);
			Edge newEdge2 = new Edge(src, weight);
			adjList.get(src).add(newEdge1);
			adjList.get(dst).add(newEdge2);
		}

		dijkstra(1);
		PrintWriter pw = new PrintWriter(new File("fortificatii.out"));
		pw.println(getMinDist());

		scanner.close();
		pw.close();
	}

}

