	ofstream fout("trenuri.out");

	string start, end;
	fin >> start >> end;  // Read the starting and ending cities

	int M;
	fin >> M;  // Read the number of connections

	map<string, vector<string>> graph;  // Adjacency list for the graph
	map<string, int> inDegree;		   // To store the in-degree of each node

	string x, y;
	for (int i = 0; i < M; i++) {
		fin >> x >> y;
		graph[x].push_back(y);  // Add the edge to the graph
		// Increment the in-degree of the destination node
		inDegree[y]++;

		if (graph.find(y) == graph.end()) {
		// Ensure every city is in the graph, even if it has no outgoing edges
			graph[y] = vector<string>();
		}

		if (inDegree.find(x) == inDegree.end()) {
			// Initialize inDegree for cities with no incoming edges
			inDegree[x] = 0;
		}
	}

	// Topological sort
	queue<string> q;
	for (auto &pair : inDegree) {
		if (pair.second == 0) {
			q.push(pair.first);  // Add nodes with in-degree 0 to the queue
		}
	}

	vector<string> topoOrder;
	while (!q.empty()) {
		string node = q.front();
		q.pop();
		topoOrder.push_back(node);  // Add node to topological order
		for (string &neighbor : graph[node]) {
			inDegree[neighbor]--;  // Reduce in-degree of neighbors
			if (inDegree[neighbor] == 0) {
				// Add neighbors with in-degree 0 to the queue
				q.push(neighbor);
			}
		}
	}

	// Longest path in DAG
	map<string, int> longestPath;
	// Start from the starting city with a path length of 1
	longestPath[start] = 1;

	for (string &node : topoOrder) {
		if (longestPath.find(node) != longestPath.end()) {
			for (string &neighbor : graph[node]) {
				// Update the longest path to each neighbor
				longestPath[neighbor] = max(longestPath[neighbor],
											longestPath[node] + 1);
			}
		}
	}

	// Output the longest path to the ending city
	fout << (longestPath[end]) << endl;

	fin.close();
	fout.close();

	return 0;
}

