import java.io.PrintStream;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import java.util.PriorityQueue;
import java.util.StringTokenizer;

public class Supercomputer {
	public static void main(final String[] args) throws IOException {
		MyScanner scanner = new MyScanner(new FileInputStream("supercomputer.in"));

		int N = scanner.nextInt(); // citim numarul de task-uri
		int M = scanner.nextInt(); // citim numarul de dependente

		int[] tasks = new int[N + 1]; // citim setul de date pentru fiecare task
		int[] incoming = new int[N + 1]; // citim nr de muchii de intrare pt fiecare nod
		for (int i = 1; i <= N; i++) {
			tasks[i] = scanner.nextInt();
		}
		// lista de adiacenta care reprezinta dependentele intre taskuri
		ArrayList<ArrayList<Integer>> adjList = new ArrayList<>(N + 1);
		for (int i = 0; i <= N; i++) {
			adjList.add(new ArrayList<>());
		}

		int[] inDegree1 = new int[N + 1];
		int[] inDegree2 = new int[N + 1];
		for (int i = 0; i < M; i++) {
			int u = scanner.nextInt();
			int v = scanner.nextInt();
			adjList.get(u).add(v);
			inDegree1[v]++;
			inDegree2[v]++;
			incoming[v] = u;
		}

		try (PrintStream printer = new PrintStream("supercomputer.out")) {
			int[] lastTaskDataSet = new int[] { -1 }; // salvam ultimul task realizat
			// sortare topologica pentru setul de date 1
			ArrayList<Integer> result1 = topoSort(N, adjList, inDegree1, tasks, lastTaskDataSet, 1);
			// sortare topologica pentru setul de date 2
			ArrayList<Integer> result2 = topoSort(N, adjList, inDegree2, tasks, lastTaskDataSet, 2);

			int switches1 = calculateSwitches(tasks, result1);
			int switches2 = calculateSwitches(tasks, result2);

			if (switches1 < switches2) {
				printer.println(switches1);
			} else {
				printer.println(switches2);
			}
		}
	}

	private static int calculateSwitches(int[] tasks, ArrayList<Integer> result) {
		int switches = 0; // contor pentru nr de switch-uri
		int lastTaskSet = -1; // retine ultimul set de date
		for (int i = 0; i < result.size(); i++) {
			// daca exista un set de date diferit fata de ultimul task
			if (lastTaskSet != -1 && lastTaskSet != tasks[result.get(i)]) {
				switches++; // actualizam (crestem) nr de switchuri
			}
			lastTaskSet = tasks[result.get(i)]; // actualizam ultimul set de date utilizat
		}
		return switches;
	}

	private static ArrayList<Integer> topoSort(int N, ArrayList<ArrayList<Integer>> adjList,
		int[] inDegree, int[] tasks, int[] lastTaskDataSet, int task) {

		List<PriorityQueue<Integer>> q = new ArrayList<>(3);
		q.add(null); // placeholder pentru index 0
		q.add(new PriorityQueue<>(Comparator.comparing(i -> inDegree[i])));
		q.add(new PriorityQueue<>(Comparator.comparing(i -> inDegree[i])));
		ArrayList<Integer> result = new ArrayList<>(); // rezultatul sortarii

		for (int i = 1; i <= N; i++) {
			if (inDegree[i] == 0) { // adaugam in coada nodurile care nu au muchii de intrare
				q.get(tasks[i]).add(i);
			}
		}

		while (!(q.get(1).isEmpty() && q.get(2).isEmpty())) { // pana cand procesam toate nodurile
			int currentTaskSet;
			// determinam setul de date curent in functie de proprietati
			if (lastTaskDataSet[0] == -1 || q.get(lastTaskDataSet[0]).isEmpty()) {
				if (lastTaskDataSet[0] != -1 && q.get(lastTaskDataSet[0]).isEmpty()) {
					currentTaskSet = lastTaskDataSet[0] == 1 ? 2 : 1;
				} else if (task == 1) {
					currentTaskSet = q.get(1).isEmpty() ? 2 : 1;
				} else {
					currentTaskSet = q.get(2).isEmpty() ? 1 : 2;
				}
			} else {
				currentTaskSet = lastTaskDataSet[0];
			}

			if (q.get(currentTaskSet).isEmpty()) {
				continue;
			}

			int node = q.get(currentTaskSet).poll(); // extragem urmatorul nod din coada
			result.add(node); // adaugam nodul la rezultat
			lastTaskDataSet[0] = tasks[node]; // actualizam ultimul set de date
			// actualizam gradul de intrare al nodurilor adiacente
			for (int v : adjList.get(node)) {
				inDegree[v]--;
				if (inDegree[v] == 0) { // daca gradul e 0 le adaugam in coada
					q.get(tasks[v]).add(v);
				}
			}
		}

		return result;
	}

	private static class MyScanner {
		private BufferedReader br;
		private StringTokenizer st;

		public MyScanner(FileInputStream fis) {
			br = new BufferedReader(new InputStreamReader(fis));
		}

		public String next() {
			while (st == null || !st.hasMoreElements()) {
				try {
					st = new StringTokenizer(br.readLine());
				} catch (IOException e) {
					e.printStackTrace();
				}
			}
			return st.nextToken();
		}

		public int nextInt() {
			return Integer.parseInt(next());
		}
	}
}

