		data_set[i] = set;
	}

	int x, y;
	for (int i = 0; i < m; i++) {
		input_file >> x >> y;
		dependecies[x].push_back(y);
	}
	input_file.close();
}

void dfs(int node) {
	// dfs recursiv
	visited[node] = 1;
	int size = dependencies[node].size();
	for (int i = 0; i < size; i++) {
		if (!visited[dependencies[node][i]]) {
			dfs(dependencies[node][i]);
		}
	}
	// adaug nodul in ordinea pentru sortarea topologica
	order.push_back(node);
}


void get_result(vector<int> order, vector<int> data_set) {
	// calculez rezultatul
	int counter = 0;
	int size = order.size();
	for (int i = 1; i < size; i++) {
		if (data_set[order[i]] != data_set[order[i - 1]]) {
			counter++;
		}
	}

	ofstream output_file;
	output_file.open("supercomputer.out");
	output_file << counter;
	output_file.close();
}

int main() {
	int n, m;
	ifstream input_file;
	input_file.open("supercomputer.in");

	input_file >> n >> m;
	vector<int> data_set_m(n + 1), visited_m(n + 1, 0), order_m;
	vector<vector<int>> dependecies_m(n + 1);
	data_set = data_set_m;
	visited = visited_m;
	order = order_m;
	dependencies = dependecies_m;
	read_data(n, m, data_set, dependencies, input_file);
	for (int i = 1; i <= n; i++) {
		if (!visited[i]) {
			dfs(i);
		}
	}
	get_result(order, data_set);
	return 0;
}

