using namespace std;

ifstream in("teleportare.in");
ofstream out("teleportare.out");

const int NMax = 10005;
long long oo = 1LL << 60;
int N, M, P;

vector<vector<pair<int, long long>>> G;

struct comp {
    bool operator()
    (const pair<int, long long> &a, const pair<int, long long> &b) {
        return a.second > b.second;
    }
};

priority_queue<pair<int, long long>, vector<pair<int, long long>>, comp> Coada;

vector<vector<long long>> deja;
bool viz[10];

// MAGIC HAPPENS HERE
// maximum number of distances is cmmmmc of teleportations
long long multiplu;
long long cmmdc(long long a, long long b) {
    if (b == 0)
        return a;
    return cmmdc(b, a % b);
}

long long cmmmc(long a, long b) {
    return (a * b) / cmmdc(a, b);
}

long long cmmmmc_total() {
    long long result = 0;
    for (int i = 1; i <= 8; i++)
    if ( viz[i]==1 ) {
        if ( result == 0 )
            result = i;
        else
            result = cmmmc(result, i);
    }
    return result;
}

// Dijsktra with a little twist
// we keep cmmmmc distances for each node
void Dijkstra() {
    int node;
    Coada.push(make_pair(1, 0));

    while (!Coada.empty()) {
        pair<int, long long> nodCurent = Coada.top();
        node = nodCurent.first;
        long long CostCurent = nodCurent.second;

        if (node == N) {
            out << CostCurent;
            return;
        }

        Coada.pop();

        for (size_t i = 0; i < G[node].size(); i++) {
            int Vecin = G[node][i].first;
            long long CostMuchie = G[node][i].second;
            if (CostMuchie < 0) {
                CostMuchie = -CostMuchie;
                if (CostCurent == 0 || CostCurent % CostMuchie == 0) {
                if ( deja[Vecin][(CostCurent+1)%multiplu] > CostCurent + 1 ) {
                    Coada.push(make_pair(Vecin, CostCurent + 1));
                    deja[Vecin][(CostCurent+1)%multiplu]= CostCurent+1;
                    }
                }
            } else {
                long long costNou = CostCurent + CostMuchie;
                if (deja[Vecin][costNou % multiplu] > costNou) {
                    Coada.push(make_pair(Vecin, costNou));
                    deja[Vecin][costNou % multiplu] = costNou;
                }
            }
        }
    }
}

int main() {
    in >> N >> M >> P;
    G.resize(N + 1);
    // add the edges to the graph
    // the teleportation edges have negative cost
    // as mark of the fact that we can use them
    // only when the cost is a multiple of their cost
    for (int i = 1; i <= M; i++) {
        int x, y, c;
        in >> x >> y >> c;
        G[x].push_back(make_pair(y, c));
        G[y].push_back(make_pair(x, c));
    }
    for (int i = 1; i <= P; i++) {
        int x, y, c;
        in >> x >> y >> c;
        G[x].push_back(make_pair(y, -c));
        G[y].push_back(make_pair(x, -c));
        if (viz[c] == 0)
            viz[c] = 1;
    }
    if ( P==0 ) {
        multiplu = 1;
    } else {
        multiplu = cmmmmc_total();
    }
    deja.resize(N + 1, vector<long long>(multiplu + 1, oo));

    Dijkstra();
    return 0;
}

