		BufferedReader inputFile = new BufferedReader(new InputStreamReader(inputStream));

		String[] line = inputFile.readLine().split(" ");
		employees = Integer.parseInt(line[0]);
		connections = Integer.parseInt(line[1]);
		adjacencyMatrix = new int[employees + 1][employees + 1];

		int contor = 0;
		while (contor != connections) {
			line = inputFile.readLine().split(" ");
			int source = Integer.parseInt(line[0]);
			int dest = Integer.parseInt(line[1]);
			adjacencyMatrix[source][dest] = 1;
			adjacencyMatrix[dest][source] = 1;
			contor ++;
		}
	}

	/**
	 * The function uses depth first search and saves in a local stack the nodes which are
	 * connected from a subset of nodes
	 * @param lostNode: the node which is removed from the network
	 * @param node: current node to evaluate
	 * @param visited:
	 * @param stack:
	 */
	public void dfs(int lostNode, int node, int[] visited, Stack<Integer> stack) {

		visited[node] = 1;
		stack.push(node);

		for (int adj = 1; adj < employees + 1; adj ++) {
			if ((adjacencyMatrix[node][adj] == 1 || adjacencyMatrix[adj][node] == 1)
				&& adj != lostNode && visited[adj] == 0) {
				dfs(lostNode, adj, visited, stack);
			}
		}
	}

	public void solve() throws IOException {

		PrintWriter printWriter = new PrintWriter(new FileWriter(outFile));

		for (int i = 1; i < employees + 1; i++) {
			int[] visited = new int[employees + 1];
			visited[i] = 1;

			/*The lost connections is initially (employees - 1), as the node which will
			  be removed can not communicate any more with the rest of computers*/
			int lost = employees - 1;
			int contor = 0;

			for (int j = 1; j < employees + 1; j++) {

				if (visited[j] != 1) {
					Stack<Integer> stack = new Stack<>();
					dfs(i, j, visited, stack);
					contor += stack.size();
					/*the lost value must increment with the sum of all the connections each
					  node from the current stack will loose*/
					lost += (employees - stack.size()) * stack.size();
					/*if all the employees have been checked 1 time, the looping must
					  stop*/
					if (contor == employees - 1) {
						break;
					}
				}
			}

			printWriter.println(lost);
		}
		printWriter.close();
	}
	public static void main(String[] args) throws IOException {
		Retea program = new Retea();

		program.readFromFile();

		program.solve();

	}
}

