    static int DFS(int query,int[] children, int steps)
    {
        int crnt = 0;
        boolean[] visited = new boolean[N];
        Stack<Integer> stack = new Stack<>();
        stack.push(query);
        while (!stack.empty()) {
            query = stack.peek();
            stack.pop();
            if (!visited[query]) {
                visited[query] = true;
            }
            Iterator<Integer> itr = graph.get(query).iterator();
            while (itr.hasNext()) {
                int v = itr.next();
                if(children[v] + crnt + 1 < steps)
                    crnt += children[v] + 1;
                else {
                    stack.push(v);
                    crnt++;
                    if(crnt == steps)
                        return v;
                    break;
                }
            }
        }
        return -1;
    }

