        import java.io.BufferedReader;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.ArrayDeque;
import java.util.Queue;

// A Queue Node
class Node {
	// `(x, y)` represents matrix cell coordinates, and
	// `dist` represents their minimum distance from the source
	int x, y, dist;

	Node(int x, int y, int dist) {
		this.x = x;
		this.y = y;
		this.dist = dist;
	}
}

public class Poduri extends Task {
	// `M × N` matrix
	private static String[][] harta;
	private static int M;
	private static int N;
	// strat point
	private static int startX;
	private static int startY;
	// output
	private static String result;
	// 4 directions
	private static final int[] row = { -1, 0, 0, 1 };
	private static final int[] col = { 0, -1, 1, 0 };

	// check if a cell could be a possible next move (not WATER, not already visited, IN matrix)
	private static boolean isValid(String[][] mat, boolean[][] visited, int row, int col) {
		return (row >= 0) && (row < N) && (col >= 0) && (col < M)
				&& !(mat[row][col].equals(".")) && !visited[row][col];
	}

	public void readData() throws IOException {
		BufferedReader read = Files.newBufferedReader(Paths.get("poduri.in"));
		String line = read.readLine();
		String[] token = line.split(" ");
		N = Integer.parseInt(token[0]);
		M = Integer.parseInt(token[1]);
		harta = new String[Integer.parseInt(token[0])][Integer.parseInt(token[1])];

		String line2 = read.readLine();
		String[] token2 = line2.split(" ");
		startX = Integer.parseInt(token2[0]);
		startY = Integer.parseInt(token2[1]);

		for (int i = 0; i < N; i++) {
			String[] lineN = read.readLine().split("");
			if (M >= 0) {
				System.arraycopy(lineN, 0, harta[i], 0, M);
			}
		}
	}

	@Override
	public String solve() {
		return null;
	}
	private static void doBfs(String[][] mat, int i, int j) {
		boolean[][] visited = new boolean[N][M];

		Queue<Node> q = new ArrayDeque<>();

		// marking the node as visited
		visited[i][j] = true;
		q.add(new Node(i, j, 0));
		// minimum distance
		int min_dist = Integer.MAX_VALUE;
		// loop till queue is empty
		label:
		while (!q.isEmpty()) {
			Node node = q.poll();
			// converting the cell info to a node
			i = node.x;
			j = node.y;
			int dist = node.dist;
			// if the GRPUND is found (from here we could rgo out of matrix),
			// update `min_dist` and BFS stops
			switch (mat[i][j]) {
				// North and South
				case "V":
					if ((i + 1 >= N) || (i - 1 < 0)) {
						min_dist = dist;
						break label;
					}
					break;
				// West and East
				case "O":
					if ((j - 1 < 0) || (j + 1 >= M)) {
						min_dist = dist;
						break label;
					}
					break;
				// all directions
				case "D":
					if ((i + 1 >= N) || (i - 1 < 0) || (j - 1 < 0) || (j + 1 >= M)) {
						min_dist = dist;
						break label;
					}
					break;
				default:
					break label;
			}

			// adding to the queue all possible, valid next moves
			if (mat[i][j].equals("V")) {
				if (isValid(mat, visited, i + 1, j)) {
					visited[i + 1][j] = true;
					q.add(new Node(i + 1, j, dist + 1));
				}
				if (isValid(mat, visited, i - 1, j)) {
					visited[i - 1][j] = true;
					q.add(new Node(i - 1, j, dist + 1));
				}
			}

			if (mat[i][j].equals("O")) {
				if (isValid(mat, visited, i, j + 1)) {
					visited[i][j + 1] = true;
					q.add(new Node(i, j + 1, dist + 1));
				}
				if (isValid(mat, visited, i, j - 1)) {
					visited[i][j - 1] = true;
					q.add(new Node(i, j - 1, dist + 1));
				}
			}

			if (mat[i][j].equals("D")) {
				for (int k = 0; k < 4; k++) {
					if (isValid(mat, visited, i + row[k], j + col[k])) {
						visited[i + row[k]][j + col[k]] = true;
						q.add(new Node(i + row[k], j + col[k], dist + 1));
					}
				}
			}
		}

		// +1 for the last move
		if (min_dist != Integer.MAX_VALUE) {
			result = String.valueOf((min_dist + 1));
		} 
	}
	public static void main(String[] args) throws IOException {
		Poduri poduri = new Poduri();
		poduri.readData();
		doBfs(harta, startX - 1, startY - 1);
		poduri.writeAnswer("poduri.out", result);
	}
}

