import java.util.ArrayDeque;
import java.util.ArrayList;
import java.util.List;
import java.util.Queue;
import java.util.SortedSet;
import java.util.TreeSet;

// Auxiliary class for storing the sums and the number of values used to compose them
class SumNode {
	int sum;
	int level;

	public SumNode(int sum, int level) {
		this.sum = sum;
		this.level = level;
	}
}

public class Lego {
	int K, N, T;

	public Lego(int k, int n, int t) {
		K = k;
		N = n;
		T = t;
	}

	// Auxiliary function to recursively compose all combinations
	private void helper(List<int[]> combinations, int[] data, int start, int end, int index) {
		if (index == data.length) {
			int[] combination = data.clone();
			combinations.add(combination);
		} else if (start <= end) {
			data[index] = start;
			helper(combinations, data, start + 1, end, index + 1);
			helper(combinations, data, start + 1, end, index);
		}
	}

	// Auxiliary function to generate a List of all possible combinations
	public List<int[]> generate(int n, int r) {
		List<int[]> combinations = new ArrayList<>();
		helper(combinations, new int[r], 1, n, 0);
		return combinations;
	}

	// Auxiliary functio which generates all possible sums using T lego pieces from
	// the combination vector
	public SortedSet<Integer> generateSumsForCombination(int[] combination) {
		SortedSet<Integer> sums = new TreeSet<>();
		Queue<SumNode> queue = new ArrayDeque<>();

		if (combination[0] == 1) {
			ArrayList<SumNode> visited = new ArrayList<>();
			for (int j : combination) {
				queue.add(new SumNode(j, 1));
			}

			while (!queue.isEmpty()) {
				SumNode currentSum = queue.poll();
				visited.add(currentSum);
				sums.add(currentSum.sum);
				if (currentSum.level < this.T) {
					for (int j : combination) {
						SumNode newSum = new SumNode(currentSum.sum + j, currentSum.level + 1);
						if (!queue.contains(newSum) && !visited.contains(newSum)) {
							queue.add(newSum);
						}
					}
				}
			}
		}

		return sums;
	}

	// Auxiliary function which returns the longest sequence of consecutive values
	public int longestConsecutiveSums(SortedSet<Integer> sums) {
		int longest = 0;
		for (int i : sums) {
			if (!sums.contains(i - 1)) {
				int streak = 0;
				while (sums.contains(i)) {
					i++;
					streak++;
					longest = Math.max(longest, streak);
				}
			}
		}
		return longest;
	}

	// Function which takes the maximum number of consecutive sums and the respective combination
	public void solve(PrintWriter writer) {
		List<int[]> combinations = this.generate(this.K, this.N);
		int[] bestCombination = combinations.get(0);
		int longestConsecutiveSums = longestConsecutiveSums(generateSumsForCombination(
			bestCombination));
		for (int[] combination : combinations) {
			int consecutiveSums = longestConsecutiveSums(generateSumsForCombination(combination));
			if (consecutiveSums > longestConsecutiveSums) {
				longestConsecutiveSums = consecutiveSums;
				bestCombination = combination;
			}
		}
		writer.println(longestConsecutiveSums);
		for (int i : bestCombination) {
			writer.print(i + " ");
		}
	}

	public static void main(String[] args) throws IOException {
		BufferedReader reader = null;
		try {
			reader = new BufferedReader(new FileReader("lego.in"));
		} catch (FileNotFoundException e) {
			System.out.println(e.getMessage());
		}

		PrintWriter writer = new PrintWriter(new FileWriter("lego.out"));

		if (reader != null) {
			String[] line = reader.readLine().split(" ");
			Lego programme = new Lego(Integer.parseInt(line[0]), Integer.parseInt(line[1]),
				Integer.parseInt(line[2]));

			programme.solve(writer);
		}
		writer.close();
	}
}

