int get_longest_subseq(set<int> a) {
    // stores the index of elements
    unordered_map<int, int> my_map;

	// longest subseq which ends in a[i]
    vector<int> dp = vector<int>(a.size() + 1, 0);

    int maximum = INT_MIN;

    // iterate for all elements of a
	for (int i = 0; i < (int)a.size(); i++) {
		int x = *next(a.begin(), i);
        // if a[i]-1 is present before i-th index
        if (my_map.find(x - 1) != my_map.end()) {
            // last index of a[i]-1
            int x2 = *next(a.begin(), i) - 1;
            int lastIndex = my_map[x2] - 1;

            dp[i] = 1 + dp[lastIndex];
        } else {
            dp[i] = 1;
        }

        my_map[x] = i + 1;

        // stores the longest length
        maximum = max(maximum, dp[i]);
    }

    return maximum;
}

void process_sol() {
	int sum = accumulate(sol.begin(), sol.end(), 0);
	sums.insert(sum);
}

void process_sums(vector<int> &dom) {
	int possible_max = get_longest_subseq(sums);

	if(possible_max > MAX) {
		MAX = possible_max;
		MAX_DOMAIN = dom;
	}
	sums.clear();
}
