void back(int cons_int, int remaining, vector<int> &sol, int MAX, int step) {
	if(!sol.empty()) {
		process_sol();
	}

	// daca nu mai am piese ramase
	if(remaining == 0) {
		return;
	}
	// incerc sa extind cu piesa i din domeniu
	for(int i = 0; i < MAX; i++) {
		// daca e epuizat, nu il mai folosesc
		int tmp = domain[i];
		if(freq[i] == 0) {
			continue;
		}
		// presupun ca e nr nou
		int new_cons_int = 1;
		if(!sol.empty() != 0 && sol.back() == tmp) {
			// am presupus gresit, e acelasi nr
			new_cons_int = cons_int + 1;
		}
		// extinde
		--freq[i];
		sol.push_back(tmp);
		back(new_cons_int, remaining - 1, sol, MAX, step + 1);
		sol.pop_back();
		++freq[i];
	}
}

void bkt(int step, int stop, vector<int> &dom) {
	if(!dom.empty() && dom.front() == 1) {
		freq = vector<int>(K + 1, T);
		back(0, T, sol, domain.size(), 0);
		process_sums(dom);
	}
	if(step == stop)
		return;
	// formez toate domeniile posibile (combinari din K luate cate N)
	int i = step == 0 ? 1 : dom.back() + 1;
	for(; i <= K; i++) {
		dom.push_back(i);
		bkt(step + 1, N, dom);
		dom.pop_back();
	}
}
