        import java.io.File;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.Scanner;



public class Statistics {
	static class Task {

		class Specialstr {
			String string;
			Integer count_occ;

			public Specialstr(String string, Integer count_occ) {
				this.string = string;
				this.count_occ = count_occ;
			}
		}
		public final  String Input_file = "statistics.in";
		public final  String Output_file = "statistics.out";

		int n;
		ArrayList<String> input_strings = new ArrayList<>();

		public void solve() {
			readInput();
			writeOutput(getResult(n, input_strings));
		}

		private void readInput() {
			try {
				Scanner sc = new Scanner(new File(Input_file));
				n = sc.nextInt();

				int cn = n + 1;
				while (cn != 0) {
					input_strings.add(sc.nextLine().toString());
					cn--;
				}
				input_strings.remove(0);
				System.out.print(input_strings.toString());
				sc.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private void writeOutput(int answer) {
			try {
				PrintWriter pw = new PrintWriter(new File(Output_file));
				pw.printf("%d\n", answer);
				pw.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}


		static int count_occurances(char c, String word) {
			int cntl = 0;
			for (int i = 0; i < word.length(); i++) {
				if (word.charAt(i) ==  c) {
					cntl++;
				}
			}
			return 2 * cntl - word.length();
		}

		private int getResult(int n, ArrayList<String> strings) {
			int j = 0;
			ArrayList<Integer> count = new ArrayList<>();
			for (char c = 'a'; c <= 'z'; c++) {
				ArrayList<Specialstr> string_list = new ArrayList<>();
				for  (int i = 0; i < strings.size(); i++) {
					Specialstr str =
						new Specialstr(strings.get(i), count_occurances(c, strings.get(i)));
					string_list.add(str);

				}
				string_list.sort((o1, o2) -> {
					return  Integer.compare(o1.count_occ, o2.count_occ);
				});
				int cnt = 0;
				int sum = 0;

				for (int i = string_list.size() - 1; i >= 0; i--) {
					sum = sum + string_list.get(i).count_occ;

					if (sum <= 0) {
						count.add(j, cnt);
						j++;
						break;
					}
					cnt++;

				}
			}
			count.sort((o1, o2) -> {
				return (-1) * o1.compareTo(o2);
			});
			if (count.size() == 0) {
				return -1;
			}
			return count.get(0);
		}
	}

	public static void main(String[] args) {
		new Task().solve();
	}
}



