        #include <bits/stdc++.h>

using namespace std;

int letterComparator;

/*
functie care ia un string, un index, si o lista de vectori de frecventa
    - ia fiecare litera din string si incrementeaza
    frecventa corespunzatoare literei din vectorul de frecventa
    aflat la pozitia index din lista de vectori de frecventa
*/
void count_letters(string word, int index, vector<vector<int>> &char_freq) {
    int sum = 0;
    for (auto &x : word) {
        char_freq[index][x - 97] += 1;
        sum += 1;
    }
    char_freq[index][26] = sum;
}

// functie folosita pentru a determina suma unui vector
int sum(vector<int> v) {
    int sum = 0;

    for (int i = 0; i < 26; i++) {
        sum += v[i];
    }

    return sum;
}

/* 
functie comparator care sorteaza doi vectori de frecventa:
    - descrescator dupa diferenta dintre frecventa literei dominante curente
    si frecventa celorlalte litere (frecv_totala - frecv litera dominanta)
    - in caz de egalitate, sorteaza descrescator dupa frecventa totala
    (stocata la pozitia 26 intr-un vector de frecventa pentru un anumit cuvant)
*/
bool comparator(vector<int> &a, vector<int> &b) {
    int len_a = a[26], len_b = b[26];
    int dif_a = a[letterComparator] - (len_a - a[letterComparator]);
    int dif_b = b[letterComparator] - (len_b - b[letterComparator]);

    if (dif_a == dif_b) {
        return len_a > len_b;
    } else {
        return dif_a > dif_b;
    }
}

int main() {
    ifstream in("statistics.in");
    ofstream out("statistics.out");

    int n, result = 0;
    in >> n;

    // initializam cate un vector de frecventa pt fiecare cuvant
    vector<vector<int>> char_freq(n, vector<int>(27, 0));

    // citim cuvant si determinam frecventele literelor
    for (int i = 0; i < n; i++) {
        string word;
        in >> word;
        count_letters(word, i, char_freq);
    }

    // pentru fiecare litera din alfabet
    for (int i = 0; i < 26; i++) {
        // sortare conform comparatorului, litera dominanta dupa
        // care se face sortarea fiind letterComparator
        letterComparator = i;
        sort(char_freq.begin(), char_freq.end(), comparator);

        int currentResult = 0, letterFreq = 0, wordLength = 0;

        // parcurgem toate cuvintele pentru a determina
        // numarul maxim de cuvinte concatenate care respecta conditia
        // frecventa litera dominanta > lungime cuvant / 2
        for (int j = 0; j < n; j++) {
            int currentWordLength = wordLength + sum(char_freq[j]);
            if (letterFreq + char_freq[j][i] > currentWordLength / 2) {
                currentResult += 1;
                letterFreq += char_freq[j][i];
                wordLength = currentWordLength;
            }
        }

        // updatam maxim global
        if (currentResult > result) {
            result = currentResult;
        }
    }

    if (result > 0) {
        out << result;
    } else {
        out << -1;
    }

    in.close();
    out.close();
}

