	private static long solveTask(String line) throws Exception {
		long nr = 1;

		for (int i = 0; i < line.length(); i++) {
			Character ch = line.charAt(i);
			if (ch.equals('u') || ch.equals('n')) {
				if (Character.isLetter(ch) && i < line.length() - 1 && Character.isDigit(line.charAt(i + 1))) {
					long value = 0;
					int j = i + 1;
					while (j < line.length() && Character.isDigit(line.charAt(j))) {
						value = value * 10 + Character.getNumericValue(line.charAt(j));
						j++;
					}
					i = j - 1;

					BigInteger x = BigInteger.valueOf(value);
					BigInteger[] res = new BigInteger[2];

					algorithm(x.add(BigInteger.ONE), res);

					nr = nr * res[0].mod(MODD).longValue();

					nr = nr % MOD;
				}
			}
		}

		return nr;
	}

	private static void algorithm(BigInteger n, BigInteger[] res) {
		BigInteger a, b, c, d;
//		BigInteger MOD = BigInteger.valueOf(1000000007);

		// Base Condition
		if (n.equals(BigInteger.ZERO)) {
			res[0] = BigInteger.ZERO;
			res[1] = BigInteger.ONE;
			return;
		}

		algorithm((n.divide(BigInteger.TWO)), res);

		// Here a = F(n)
		a = res[0];

		// Here b = F(n+1)
		b = res[1];

		c = b.multiply(BigInteger.TWO).subtract(a);

		if (c.compareTo(BigInteger.ZERO) < 0) {
			c = c.add(MODD);
		}

		// As F(2n) = F(n)[2F(n+1) – F(n)]
		// Here c = F(2n)
		c = a.multiply(c).mod(MODD);

		// As F(2n + 1) = F(n)^2 + F(n+1)^2
		// Here d = F(2n + 1)
		BigInteger a1 = a.multiply(a);
		BigInteger b1 = b.multiply(b);
		d = a1.add(b1).mod(MODD);

		// Check if N is odd
		// or even
		if (n.mod(BigInteger.TWO).equals(BigInteger.ZERO)) {
			res[0] = c;
			res[1] = d;
		} else {
			res[0] = d;
			res[1] = c.add(d);
		}
	}

