bool compare_words(string word1, string word2, char c) {
	double ratio1 = (double)count_occurrences(word1, c) / word1.size();
	double ratio2 = (double)count_occurrences(word2, c) / word2.size();

	if (ratio1 != ratio2)
		return ratio1 > ratio2;
