import java.io.IOException;
import java.io.PrintWriter;
import java.util.Arrays;
import java.util.HashMap;
import java.util.Map;
import java.util.PriorityQueue;
import java.util.Scanner;

public class Criptat {
	public static final String INPUT_FILE = "criptat.in";
	public static final String OUTPUT_FILE = "criptat.out";

	int n;  // numarul cuvintelor
	String[] s;  // cuvintele

	public void solve() {
		readInput();
		writeOutput(getResult());
	}

	private void readInput() {
		try (Scanner sc = new Scanner(new BufferedReader(
				new FileReader(INPUT_FILE)))) {
			n = sc.nextInt();
			s = new String[n];
			for (int i = 0; i < n; i++) {
				s[i] = sc.next();
			}
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	private void writeOutput(int result) {
		try {
			PrintWriter pw = new PrintWriter(new BufferedWriter(
					new FileWriter(OUTPUT_FILE)));
			pw.printf("%d\n", result);
			pw.close();
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	private int getResult() {
		// retinem frecventa fiecarui caracter intr-un hashmap
		Map<Character, Integer> freq = new HashMap<>();
		// iteram prin toate cuvintele din sir, si apoi prin toate caracterele
		for (String word : s) {
			for (char c : word.toCharArray()) {
				freq.put(c, freq.getOrDefault(c, 0) + 1);
			}
		}

		// retinem parola cea mai lunga
		StringBuilder maxPassword = new StringBuilder();
		// stocam caracterele in ordine inversa dupa frecventa
		PriorityQueue<Character> maxHeap = new PriorityQueue<>((a, b) -> freq.get(b) - freq.get(a));
		// adaugam toate caracterele in maxHeap din freq
		maxHeap.addAll(freq.keySet());

		while (!maxHeap.isEmpty()) {
			// extragem caracterul cu cea mai mare frecventa
			char maxFreqChar = maxHeap.remove();

			// sortam s in ordine descrescatoare dupa frecventa caracterului
			Arrays.sort(s, (a, b) -> {
				int freqA = countFreq(a, maxFreqChar);
				int freqB = countFreq(b, maxFreqChar);
				return Double.compare((double) freqB / b.length(), (double) freqA / a.length());
			});

			int totalChars = 0, totalFreq = 0;
			// stocam parola curenta
			StringBuilder password = new StringBuilder();

			// iteram prin toate cuvintele sortate
			for (String word : s) {
				// calculam frecventa caracterului in cuvant
				int wordFreq = countFreq(word, maxFreqChar);
				// daca, adaugand cuvantul, crestem raportul dintre frecventa
				// totala si lungimea totala, adaugam cuvantul la parola
				if ((totalFreq + wordFreq) * 2 > totalChars + word.length()) {
					totalChars += word.length();
					totalFreq += wordFreq;
					password.append(word);
				}
			}

			if (password.length() > maxPassword.length()) {
				maxPassword = password;
			}

			// eliminam caracterul cu cea mai mare frecventa
			freq.remove(maxFreqChar);
		}

		return maxPassword.length();
	}

	// calculeaza frecventa unui caracter intr-un cuvant
	private int countFreq(String word, char c) {
		int count = 0;
		for (char ch : word.toCharArray()) {
			if (ch == c) {
				count++;
			}
		}
		return count;
	}

	public static void main(String[] args) {
		new Criptat().solve();
	}
}

