    vector<unsigned long long> dist(n + 1, UINT64_MAX);
    dist[start] = 0;
    set<pair<int, int>> s;  // dist, nod
    s.insert({0, start});

    while (!s.empty()) {
        pair<int, int> top = *s.begin();
        s.erase(s.begin());
        int currentNode = top.second;
        for (int i = 0; i < neigh[currentNode].size(); i++) {
            int nextNode = neigh[currentNode][i].first;
            int addedCost = neigh[currentNode][i].second;
            if (dist[currentNode] + addedCost < dist[nextNode]) {
                dist[nextNode] = dist[currentNode] + addedCost;
                s.insert({dist[nextNode], nextNode});
            }
        }
    }
    return dist;
}

int main() {
    if (!fin.is_open()) {
        cerr << "Fisierul nu a putut fi deschis\n";
        return 1;
    }
    int n, m;
    fin >> n >> m;
    // Output nodes from every node
    vector<vector<pair<int, int>>> out1(n + 1);
    // Input nodes to every node
    vector<vector<pair<int, int>>> in1(n + 1);

    // Read input
    for (int i = 0; i < m; i++) {
        int a, b, c;
        fin >> a >> b >> c;
        out1[a].push_back({b, c});
        in1[b].push_back({a, c});
    }

    // Read sources and destination
    int x, y, z;
    fin >> x >> y >> z;
    // Get the distances from x to every other node
    vector<unsigned long long> dist1 = dijkstra(n, x, out1);

    // Get the distances from y to every other node
    vector<unsigned long long> dist2 = dijkstra(n, y, out1);

    // Get the distances from z to every other node
    vector<unsigned long long> dist3 = dijkstra(n, z, in1);

    // Find the minimum sum of distances
    unsigned long long minDist = UINT64_MAX;
    for (int i = 1; i <= n; i++) {
        if (dist1[i] == UINT64_MAX || dist2[i] == UINT64_MAX
                || dist3[i] == UINT64_MAX) {
            continue;
        }
        unsigned long long dist = dist1[i] + dist2[i] + dist3[i];
        if (dist < minDist) {
            minDist = dist;
        }
    }

    fout << minDist << endl;
    return 0;
}

