using namespace std;

#define INF     (((long long)1 << 60) - 1)

struct pair_comparator {
    bool operator()(const pair<int, long long>& a,
                    const pair<int, long long>& b) {
        return a.second > b.second;
    }
};

class Task {
 public:
    explicit Task(const char *filein);
    void solve(const char *fileout) {
        ofstream(fileout) << compute_minimum_value();
    }

 private:
    vector<vector<pair<int, long long>>> adj;

    // store reversed nodes so we can efficiently find distances from every
    // node to z
    vector<vector<pair<int, long long>>> adj_reversed;
    int x, y, z;

    void Dijkstra(vector<long long>& dist, int source);
    long long compute_minimum_value();
};

Task::Task(const char *filein) {
    ifstream fin(filein);

    int N, M;

    fin >> N >> M;
    adj = adj_reversed = vector<vector<pair<int, long long>>>(N + 1);

    while (M--) {
        int a, b, c;
        fin >> a >> b >> c;

        adj[a].push_back({b, c});
        adj_reversed[b].push_back({a, c});
    }

    fin >> x >> y >> z;
}

void Task::Dijkstra(vector<long long>& dist, int source) {
    dist = vector<long long>(adj.size(), INF);
    priority_queue<pair<int, long long>,
                    vector<pair<int, long long>>,
                    pair_comparator> pq;

    dist[source] = 0;
    pq.push({source, 0});

    while (!pq.empty()) {
        pair<int, int> current = pq.top();
        pq.pop();

        if (current.second > dist[current.first]) {
            continue;
        }

        for (const auto& neighbours : adj[current.first]) {
            if (dist[neighbours.first] > neighbours.second
                                            + dist[current.first]) {
                dist[neighbours.first] = neighbours.second
                                            + dist[current.first];
                pq.push({neighbours.first, dist[current.first]});
            }
        }
    }
}

long long Task::compute_minimum_value() {
    vector<long long> x_to_everyone, y_to_everyone, everyone_to_z;

    Dijkstra(x_to_everyone, x);
    Dijkstra(y_to_everyone, y);

    // we must find min(dist(x, node) + dist(y, node) + dist(node, z)),
    // with node in nodes; for optimization, calculate this minimum while
    // applying Dijkstra from z to everyone, with reversed adj
    vector<long long> dist = vector<long long>(adj_reversed.size(), INF);
    priority_queue<pair<int, long long>,
                    vector<pair<int, long long>>,
                    pair_comparator> pq;

    long long min = INF;

    dist[z] = 0;
    pq.push({z, 0});

    while (!pq.empty()) {
        pair<int, int> current = pq.top();
        pq.pop();

        if (current.second > dist[current.first]) {
            continue;
        }

        long long current_min = x_to_everyone[current.first]
                                + y_to_everyone[current.first]
                                + dist[current.first];

        if (current_min < min) {
            min = current_min;
        }

        for (auto& neighbours : adj_reversed[current.first]) {
            if (dist[neighbours.first] > neighbours.second
                                            + dist[current.first]) {
                dist[neighbours.first] = neighbours.second
                                            + dist[current.first];
                pq.push({neighbours.first, dist[current.first]});
            }
        }
    }

    return min;
}

int main() {
