    int i, j, k;
    int gradInterior, poz;
    int copieM;

    fin >> n >> m >> a;

    double graf[m+10][m+10];
    long v1[n+1], v2[n+1];
    double viz[m+10];

    for (i=1; i <= n; i++)
        fin >> v1[i];  // O(n)

    for (i=2; i <= a; i++) {  // O(a)
        for (j=1; j <= n; j++)  // O(n)
            fin >> v2[j];

        poz = 1;
        while (v1[poz] == v2[poz]) {  // vreau sa ajung la
                                     // primele 2 elemente diferite
            poz++;  // O(n)
        }

        graf[v1[poz]][v2[poz]] = 1;

        for (int k=1; k <= n; k++)  // O(n)
            v1[k] = v2[k];
    }

    for (i=1; i <= m; i++)  // O(m)
        viz[i] = 0;  // toate nodurile sunt nevizitate

    copieM = m;
    while (copieM > 0) {  // O(m)
        for (j=1; j <= m; j++) {  //  O(m) posibilele masini cu grad 0
            if (viz[j] == 0) {
                // parcurgem coloana lui j ca sa aflam gradul interior
                // al acestuia
                gradInterior = 0;

                for (i=1; i <= m; i++)  // O(m)
                    if (graf[i][j] == 1)
                        gradInterior++;

                if (gradInterior == 0) {
                    fout << j << ' ';
                    viz[j] = 1;

                    // facem toata linia lui j = 0 (eliminam
                    // toate muchiile care pleaca din j)
                    for (k=1; k <= m; k++)  // O(m)
                        graf[j][k] = 0;

                    break;
                }
            }
        }
       --copieM;
    }
    // O(m^3)
    fout<<"\n";
    fin.close();
    fout.close();
    return 0;
}
