    // pentru fiecare platou  O(2*m*W*n)
    for (int i = 1; i <= 2* m; i++) {
        // pentru fiecare pret
        for (int j = 1; j <= W; j++) {
		  // pentru fiecare maxim n platouri
			for (int k = 1; k <= n; k++) {
				dp[i][j][k] = dp[i-1][j][k];

				// daca avem buget pentru platou
				if (j - newprices[i - 1] >= 0) {
