        import java.io.File;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.Scanner;


public class Prinel {

	static class Task {
		public final String Input = "prinel.in";
		public final String Output = "prinel.out";

		int n;
		int k;
		int maxElem;
		int sol;
		int[] auxiliar;
		int[] target;
		int[] points;
		int[] operations;



		public void solve() {
			readInput();
			writeOutput(getResult());
		}


		private void readInput() {
			try {
				Scanner sc = new Scanner(new File(Input));
				n = sc.nextInt();
				k = sc.nextInt();
				target = new int[n];
				points = new int[n];
				for (int i = 0; i < n; i++) {
					target[i] = sc.nextInt();
				}
				for (int i = 0; i < n; i++) {
					points[i] = sc.nextInt();
				}
				sc.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private void writeOutput(int count) {
			try {
				PrintWriter pw = new PrintWriter(new File(Output));
				pw.printf("%d\n", count);
				pw.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private void calculateOperations(int maxElem) {
			operations = new int[maxElem + 1];
			for (int i = 2; i <= maxElem; i++) {
				operations[i] = Integer.MAX_VALUE;
			}

			for (int i = 1; i <= maxElem; i++) {
				for (int j = 1; j <= i / j; j++) {
					if ((i % j == 0) && i + j <= maxElem) {
						operations[i + j] = Math.min(operations[i + j], operations[i] + 1);
					}
					if ((i % (i / j) == 0) && (i + (i / j) <= maxElem)) {
						operations[i + i / j] = Math.min(operations[i + i / j], operations[i] + 1);
					}
				}
			}
		}

		private void calculateMaxElem(int[] vector) {
			maxElem = Integer.MIN_VALUE;
			for (int elem : vector) {
				if (elem > maxElem) {
					maxElem = elem;
				}
			}
		}

		private void getOperatios() {
			auxiliar = new int[n];
			for (int i = 0; i < n; i++) {
				auxiliar[i] = operations[target[i]];
			}
		}


		private int getResult() {
			calculateMaxElem(target);
			calculateOperations(maxElem);
			getOperatios();
			int[] dp = new int[n * k + 1];

			for (int i = 0; i < n; i++) {
				for (int j = k - auxiliar[i]; j >= 0; j--) {
					dp[j + auxiliar[i]] = Math.max(dp[j + auxiliar[i]], dp[j] + points[i]);
				}
			}
			sol = dp[k];
			return sol;
		}
	}

	public static void main(String[] args) {
		new Task().solve();
