import java.io.PrintWriter;

public class Walsh {
	static class Task {
		int n, k;
		BufferedReader bufferedReader;
		PrintWriter printWriter;

		private void solve() {
			init();
			for (int i = 0; i < k; i++) {
				int x, y;
				String line = null;
				try {
					line = bufferedReader.readLine();
				} catch (IOException e) {
					e.printStackTrace();
				}
				//getting x and y from the line
				String[] lineElements = line.split(" ", 2);
				x = Integer.parseInt(lineElements[0]);
				y = Integer.parseInt(lineElements[1]);
				if (walshSolver(n, x, y)) {
					printWriter.write("1\n");
				} else {
					printWriter.write("0\n");
				}
			}
			printWriter.close();
		}

		private void init() {
			try {
				bufferedReader = new BufferedReader(new FileReader("walsh.in"));
				printWriter = new PrintWriter(new File("walsh.out"));
				String line = bufferedReader.readLine();
				//getting n and k from the line
				String[] lineElements = line.split(" ");
				this.n = Integer.parseInt(lineElements[0]);
				this.k = Integer.parseInt(lineElements[1]);
			} catch (FileNotFoundException e) {
				e.printStackTrace();
			} catch (IOException e) {
				e.printStackTrace();
			}
		}

		private boolean walshSolver(int n, int x, int y) {
			if (n == 1) {
				return false;
			}
			//in order to not calculate it more than once
			int halfN = (n >> 1);
			if (x <= halfN && y <= halfN) { //zone 1
				//we should change x and y to have coordinates for our next zone
				return walshSolver(halfN, x, y);
			}
			if (x <= halfN && y > halfN) { //zone 2
				return walshSolver(halfN, x, y - halfN);
			}
			if (x > halfN && y <= halfN) { //zone 3
				return walshSolver(halfN, x - halfN, y);
			}
			if (x > halfN && y > halfN) { //zone 4
				//from the walsh formula in zone 4 we negate the answer
				return !walshSolver(halfN, x - halfN, y - halfN);
			}
			return false;
		}
	}

	public static void main(String[] args) {
		new Task().solve();
	}
}

