        import java.io.File;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

public class Numarare {
	static int N, M;
	static final long MOD = (long) 1e9 + 7;

	public static void main(String[] args) throws IOException {
		String inputFilename = "numarare.in";
		String outputFilename = "numarare.out";

		try (Scanner scanner = new Scanner(new File(inputFilename))) {
			N = scanner.nextInt();
			M = scanner.nextInt();

			// initializez grafurile
			List<List<Integer>> graful1 = new ArrayList<>(N);
			List<List<Integer>> graful2 = new ArrayList<>(N);

			// initializarea listelor interne pentru fiecare nod din grafuri
			for (int i = 0; i < N; i++) {
				graful1.add(new ArrayList<>());
				graful2.add(new ArrayList<>());
			}

			// citesc muchiile pentru fiecare graf in parte
			for (int i = 0; i < M; i++) {
				int x = scanner.nextInt() - 1;
				int y = scanner.nextInt() - 1;
				graful1.get(x).add(y);
			}

			for (int i = 0; i < M; i++) {
				int x = scanner.nextInt() - 1;
				int y = scanner.nextInt() - 1;
				graful2.get(x).add(y);
			}

			// intializez un vector de drumuri cu 1 pentru nodul de start
			long[] dp = new long[N];
			dp[0] = 1;

			for (int i = 0; i < N; i++) {
				// parcurg vecinii nodului i din ambele grafuri
				for (int vecin1 : graful1.get(i)) {
					for (int vecin2 : graful2.get(i)) {
						// daca un vecin este acelasi in ambele grafuri
						// adaug numarul de drumuri catre acel vecin din nodul i
						if (vecin1 == vecin2) {
							dp[vecin1] = (dp[vecin1] + dp[i]) % MOD;
							// astfel asigur doar numararea a drumurilor care impart
							// un vecin comun intre cele 2 grafuri
						}
					}
				}
			}

			// rezultatul final
			long result = 0;

			for (int i = 0; i < N; i++) {
				// verific daca nodul i nu are vecini in ambele grafuri
				if (graful1.get(i).isEmpty() && graful2.get(i).isEmpty()) {
					// daca nu are adaug numarul de drumuri catre el la rezultat
					result = (result + dp[i]) % MOD;
				}
			}

			try (PrintWriter pw = new PrintWriter(new File(outputFilename))) {
				pw.println(result);
			}

		} catch (IOException e) {
			e.printStackTrace();
		}
	}
}

