        #include <fstream>
#include <vector>
#include <unordered_set>
#include <iostream>
using namespace std;

const int MOD = 1000000007;

vector<vector<int>> adj;
vector<int> dp;
vector<bool> visited;

int dfs(int node, int N) {
    if (node == N)
        return 1;

    if (visited[node])
        return dp[node];

    visited[node] = true;

    if (adj[node].empty()) {
        dp[node] = 0;
        return dp[node];
    }

    for (int next : adj[node]) {
        dp[node] += dfs(next, N);
        dp[node] %= MOD;
    }

    return dp[node];
}

int main() {
    ifstream fin("numarare.in");
    ofstream fout("numarare.out");

    int N, M;
    fin >> N >> M;

    if (N <= 0 || M < 0) {
        cerr << "Valori invalide pentru N si M" << endl;
        return 1;
    }

    vector<unordered_set<int>> graph1(N + 1), graph2(N + 1);
    int x, y;

    for (int i = 0; i < M; ++i) {
        fin >> x >> y;
        graph1[x].insert(y);
    }

    for (int i = 0; i < M; ++i) {
        fin >> x >> y;
        if (graph1[x].find(y) != graph1[x].end())
            graph2[x].insert(y);
    }

    adj.resize(N + 1);
    for (int i = 1; i <= N; ++i) {
        for (int j : graph2[i])
            adj[i].push_back(j);
    }

    dp.resize(N + 1, 0);
    visited.resize(N + 1, false);

    int result = dfs(1, N);

    fout << result % MOD << endl;

    fin.close();
    fout.close();

    return 0;
}

