        import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.Scanner;

public class Colorare {
	static class TaskTwo {
		int K;
		int[] X;
		char[] T;
		int modulo = 1000000007;

		public void solve() {
			readInput();
			writeOutput(getResult());
		}

		private long getResult() {
			long res;
			if (T[0] == 'H') {  // primul caracter
				res = (2 * pow(3, X[0])) % modulo;
			} else {
				res = (3 * pow(2, X[0] - 1)) % modulo;
			}
			for (int i = 1; i < K; i++) {
				if (T[i] == 'H' && T[i - 1] == 'H') {  // H dupa H
					res = (res * pow(3, X[i])) % modulo;
				} else if (T[i] == 'H' && T[i - 1] == 'V') {  // H dupa V
					res = (res * 2 * pow(3, X[i] - 1)) % modulo;
				} else if (T[i] == 'V' && T[i - 1] == 'H') {  // V dupa H
					res = (res * pow(2, X[i] - 1)) % modulo;
				} else if (T[i] == 'V' && T[i - 1] == 'V') {  // V dupa V
					res = (res * pow(2, X[i])) % modulo;
				}
			}
			return res;
		}

		private long pow(int base, int power) {
			long result;
			if (power == 0) {
				return 1;
			}
			result = pow(base, power / 2);
			if (power % 2 == 0) {
				return (result * result) % modulo;
			} else {
				return (base * result * result) % modulo;
			}
		}


		private void readInput() {
			try {
				Scanner sc = new Scanner(new BufferedReader(new FileReader("colorare.in")));
				K = sc.nextInt();
				X = new int[K];
				T = new char[K];
				for (int i = 0; i < K; i++) {
					X[i] = sc.nextInt();
					T[i] = sc.next().charAt(0);
				}
				sc.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private void writeOutput(long res) {
			try {
				PrintWriter pw = new PrintWriter(new BufferedWriter(
						new FileWriter("colorare.out")));
				pw.printf("%d\n", res);
				pw.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}
	}
	public static void main(String[] args) {
		TaskTwo task = new TaskTwo();
		task.solve();
	}
}

