        #include <bits/stdc++.h>
using namespace std;

#define MOD (int)(1e9 + 7)

class Crypto {
 public:
    int N, L;
    string myKey;
    string mySubstring;
    int myUniq;

void solve() {
        ifstream fin("crypto.in");
        fin >> N >> L;
        ofstream fout("crypto.out");

        fin >> myKey;
        fin >> mySubstring;
        myUniq = countUnique(mySubstring);

        fout << getResault();
        fin.close();
        fout.close();
}
// Identifica numarului unic de caractere
int countUnique(string s) {
    vector<bool> aux(26, 0);
    int i, cnt = 0;
    for (i = 0; i < s.length(); i ++)
        if (aux[s[i] - 'a'] == false) {
            aux[s[i] - 'a'] = true;
            cnt ++;
        }
    return cnt;
}
// Folosind DI calculez atat produsul cat si
// ridicarea la putere in O(sqrt N)
long long myMultiply(long long a, long long b) {
        if (!b) {
            return 0;
        }
        if (b == 1) {
            return a % MOD;
        }
        long long ans = (myMultiply(a, b / 2) * 2) % MOD;

        if (b % 2 == 1) {
            return (a + ans) % MOD;
        }
        return ans;
}

long long myPow(long long base, long long exponent) {
        if (exponent == 0) {
            return 1;
        }

        if (exponent == 1) {
            return base % MOD;
        }

        long long temp = myPow(base, exponent / 2);

        if (exponent % 2 == 0) {
            return myMultiply(temp, temp) % MOD;
        }
        return myMultiply(myMultiply(temp, temp) % MOD, base) % MOD;
}
// Functia principala de prelucrare ce realizeaza completarea
// matricei DP si ofera raspunsul.
int myCount(string a, string b, int m, int n,
          vector<vector<int>>& dp, vector<int> &countQM) {
    if ((m == 0 && n == 0) || n == 0) {
        if (countQM[m] == -1)
            countQM[m] = count(a.begin(), a.begin() + m, '?');

        return (myPow(myUniq, countQM[m])) % MOD;
    }

    if (m == 0)
        return 0;

    if (dp[m][n] != -1) {
        return dp[m][n];
    }

    if (a[m - 1] == '?')
        return dp[m][n] = (myCount(a, b, m - 1, n - 1, dp, countQM) % MOD
                        + (1LL * myUniq *(myCount(a, b, m - 1, n, dp, countQM))
                           % MOD) % MOD) % MOD;

    if (a[m - 1] == b[n - 1])
        return dp[m][n] = (myCount(a, b, m - 1, n - 1, dp, countQM) % MOD
                          + myCount(a, b, m - 1, n, dp, countQM) %  MOD) % MOD;
    else
        return dp[m][n] = myCount(a, b, m - 1, n, dp, countQM) % MOD;
}

int getResault() {
    char c = 'a';
    vector<vector<int>> dp(N + 1, vector<int>(L + 1, -1));
    vector<int> countQM(N, -1);
    int myResault = myCount(myKey, mySubstring, N, L, dp, countQM);

    return myResault;
}
};
int main(void) {
    auto* task = new (nothrow) Crypto();
    if (!task) {
        cerr << "allocation failed\n";
        return -1;
    }

    task->solve();
    delete task;
    return 0;
}

