        #include <iostream>
#include <fstream>
#include <vector>
#include <iomanip>
#include <numeric>
#include <cmath>

using namespace std;

double power(double cost, int N, const vector<int>& P, const vector<int>& C) {
    double min_pow = 1000000000;
    for (int i = 0; i < N; i++) {
        double current = P[i] - abs(C[i] - cost);
        if (current < min_pow) {
            min_pow = current;
        }
    }
    return min_pow;
}

double best(double lower, double upper, int N,
                                const vector<int>& P, const vector<int>& C) {
    double power_of_lower = power(lower, N, P, C);
    double power_of_upper = power(upper, N, P, C);
    double middle = (lower + upper) / 2.0;

    if (abs(power_of_lower - power_of_upper) <= 0.1) {
        return power(middle, N, P, C);
    }

    if (power_of_lower < power_of_upper) {
        return best(middle, upper, N, P, C);
    } else {
        return best(lower, middle, N, P, C);
    }
}

int main() {
    ifstream fin("servere.in");
    ofstream fout("servere.out");

    int N;
    fin >> N;

    vector<int> P(N);  // puteri
    vector<int> C(N);  // praguri

    int range_lower = 1000000001;
    int range_upper = 0;

    for (int i = 0; i < N; i++) {
        fin >> P[i];
    }

    for (int i = 0; i < N; i++) {
        fin >> C[i];
        range_lower = min(range_lower, C[i]);
        range_upper = max(range_upper, C[i]);
    }

    double bestish = best(range_lower, range_upper, N, P, C);

    fout << fixed << setprecision(1) << bestish << "\n";

    fin.close();
    fout.close();

    return 0;
}

