int N, M, S;
int lines;

int min(int a, int b) {
    return a > b ? b : a;
}
vector<int> node_stack;
vector<int> low_link, component;
int new_component;

void dfs(int node, vector<int>& parent, int& timestamp, vector<int>& found,
    vector<int>& low_link) {

    found[node] = ++timestamp;
    low_link[node] = found[node];
    node_stack.push_back(node);

    for (int neigh : adj[node]) {
        if (parent[neigh] != -1) {
            auto found_in_stack =
                find(node_stack.begin(), node_stack.end(), neigh);
            if (found_in_stack != node_stack.end()) {
                low_link[node] = min(low_link[node], found[neigh]);
            }

            continue;
        }

        parent[neigh] = node;
        dfs(neigh, parent, timestamp, found, low_link);
        low_link[node] = min(low_link[node], low_link[neigh]);
    }

    if (low_link[node] == found[node]) {
        int x;
        new_component++;

        do {
            x = node_stack.back();
            node_stack.pop_back();
            component[x] = new_component;
        } while (x != node && !node_stack.empty());
    }
}

void tarjan_nebun() {
    vector<int> parent(N+1), found(N+1);
    low_link.push_back(-1);

    for (int i = 1; i <= N; i++) {
        parent[i] = -1;
        found[i] = INT_MAX - 1;
        low_link.push_back(INT_MAX - 1);
        component.push_back(-1);
    }

    int timestamp = 0;
    for (int i = 1; i <= N; i++) {
        if (parent[i] == -1) {
            parent[i] = i;

            dfs(i, parent, timestamp, found, low_link);
        }
    }
}

void read() {
    ifstream in("ferate.in");

    in >> N >> M >> S;
    adj = new vector<int>[N + 1];

    for (int i = 1; i <= M; i++) {
        int a, b;
        in >> a >> b;

        adj[a].push_back(b);
        edge_list.push_back(make_pair(a, b));
    }
}

int main() {
    ofstream out("ferate.out");

    read();
    tarjan_nebun();

    vector<bool> connected(N+1);
    connected[component[S]] = true;


    for (pair<int, int> x : edge_list) {
        int comp = component[x.second];

        if (comp != component[x.first]) {
            connected[comp] = true;
        }
    }

    for (int i = 1; i <= new_component; i++) {
        if (connected[i] == false) {
            lines++;
        }
    }

    out << lines << "\n";
}

