        #include <iostream>
#include <fstream>
using namespace std;

ofstream outputFile;
ifstream inputFile;
int nOrase;
unsigned long long cOrase[2010], nrIntrebari;

/*
    Cautare binara pe vectorul dp2 care este deja
    sortat crescator. Se cauta nrNegustori.
*/
void nrMaximOrase(unsigned long long nrNegustori,
                  unsigned long long dp2[]) {
    int left, right, mid;

    left = 1;
    right = nOrase;
    while (left <= right) {
        mid = (left + right) / 2;
        if (nrNegustori < dp2[mid]) {
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    outputFile << left - 1  << endl;
}

int main() {
    inputFile.open("regele.in", ios::in);
    outputFile.open("regele.out", ios::out);

    /*
        Citesc nOrase si coordonatele si
        fac prelucrarile initiale, adica populez matricea
        dp1[][] si vectorul dp2[]. Ulterior voi interoga
        vectorul dp2.
    */
    inputFile >> nOrase;
    for (int i = 1; i <= nOrase; ++i) {
        inputFile >> cOrase[i];
    }

    // Populez vectorul costurilor de activare pt. fiecare oras.
    unsigned long long c_activ_orase[nOrase + 1];
    c_activ_orase[1] = cOrase[2] - cOrase[1];
    c_activ_orase[nOrase] = cOrase[nOrase] - cOrase[nOrase - 1];
    for (int i = 2; i < nOrase; ++i) {
        c_activ_orase[i]  = cOrase[i] - cOrase[i-1];
        c_activ_orase[i] += cOrase[i+1] - cOrase[i];
    }

    /*
        Populez matricea dp1[nOrase+1][nOrase+1]
        si vectorul dp2[nOrase+1].
        *** dp1[i][j] = nr-ul maxim de negustori necesari pt. a activa
                        i orase de la stanga la dreapta
                        dintre care primul este j obligatoriu
        *** dp2[i] = nr-ul maxim de negustori necesari pt. a activa
                     un tuplu de i orase oarecare.
    */
    unsigned long long linia_a[nOrase + 1];
    unsigned long long linia_b[nOrase + 1];
    unsigned long long dp2[nOrase + 1], max, max_ant;

    // Linia 1 din matrice si elementul 1 din vector.
    max = 0;
    for (int j = 1; j <= nOrase; ++j) {
        linia_a[j] = c_activ_orase[j];
        if (max < linia_a[j]) {
            max = linia_a[j];
        }
    }
    dp2[1] = max;

    /*
        Penultima si ultima linie din matrice pot
        sa ramana necompletate pentru ca valoarea maxima
        de pe ele este deja cunoscuta.
    */
    dp2[nOrase - 1] = cOrase[nOrase] - cOrase[1];
    dp2[nOrase] = dp2[nOrase - 1];

    // Completez restul matricei.
    for (int i = 2; i <= nOrase - 2; ++i) {
        linia_b[nOrase - (i - 1)] = cOrase[nOrase] - cOrase[nOrase - i];
        max = linia_b[nOrase - (i - 1)];
        max_ant = 0;
        for (int j = nOrase - i; j >= 1; --j) {
            linia_b[j] = c_activ_orase[j];

            if (linia_a[j + 2] > max_ant) {
                max_ant = linia_a[j + 2];
            }

            linia_b[j] += max_ant;

            if (linia_b[j] > max) {
                max = linia_b[j];
            }
        }
        for (int j = 1; j <= nOrase - i + 1; ++j) {
            linia_a[j] = linia_b[j];
        }
        dp2[i] = max;
    }

    /*
        Incep sa raspund la intrebari.
    */
    inputFile >> nrIntrebari;
    for (unsigned long long i = 1; i <= nrIntrebari; ++i) {
        unsigned long long nrNegustori;
        inputFile >> nrNegustori;
        nrMaximOrase(nrNegustori, dp2);
    }

    inputFile.close();
    outputFile.close();
    return 0;
}

