        #include <bits/stdc++.h>
using namespace std;

unsigned int dp[2005][2005];
unsigned int merchants[500005];

class Task {
 public:
    void solve() {
        read_input();
        compute();
    }

 private:
    unsigned int q;
    unsigned int n;
    unsigned long int coord[2005];


    void read_input() {
        ifstream fin("regele.in");
        fin >> n;

        for (unsigned int i = 0; i < n; ++i) {
            fin >> coord[i];
        }

        fin >> q;

        for (unsigned int i = 0; i < q; ++i) {
            fin >> merchants[i];
        }

        fin.close();
    }

    void compute() {
        /* The cost of a city = city_right_neighbour - city_left_neighbour
        * If it is a 'left border' city then city_right_neighbour - crt_city
        * If it is a 'right border' city then crt_city - city_left_neighbour
        */

        /* For the first j cities, find the maximum no. of merchants that is
        * needed to activate i cities.
        * The result will be on the last column, so store this column in an
        * array.
        */

        unsigned int crt_cost;
        unsigned int max_merchants[2005];
        unsigned int k = 0;

        for (unsigned int i = 1; i <= n; ++i) {
            for (unsigned int j = 0; j < n; ++j) {
                if (j == 0) {
                    crt_cost = coord[1] - coord[0];
                } else if (j == n - 1) {
                    crt_cost = coord[n - 1] - coord[n - 2];
                } else {
                    crt_cost = coord[j + 1] - coord[j - 1];
                }

                if (j >= 2) {
                    dp[i][j] = max(dp[i][j - 1], dp[i - 1][j - 2] + crt_cost);
                } else {
                    dp[i][j] = crt_cost;
                }

                if (j == n - 1) {
                    max_merchants[k++] = dp[i][j];
                }
            }
        }

        /* For each number of merchants, count how many times it is less or
        * equal than the value on the last column.
        */
        ofstream fout("regele.out");
        for (unsigned int i = 0; i < q; ++i) {
            // Find the first index greater than the current no. of merchants.
            auto idx = upper_bound(max_merchants, max_merchants + k,
                                   merchants[i]);

            fout << (idx - max_merchants) << '\n';
        }

        fout.close();
    }
};

int main() {
    auto *task = new Task();
    task->solve();
    delete task;
    return 0;
}

