        #include <iostream>
#include <fstream>
#include <bits/stdc++.h>

using namespace std;
typedef struct comp{
	int power;
	int price;
}Computer;
//https://www.geeksforgeeks.org/quick-sort/
void swap(Computer* a, Computer* b){
    Computer t = *a;
    *a = *b;
    *b = t;
}

int partition (Computer arr[], int low, int high){
   	Computer pivot = arr[high];
    int i = (low - 1);
    for (int j = low; j <= high - 1; j++){  
        if (arr[j].power < pivot.power){
            i++;
            swap(&arr[i], &arr[j]);
        }
    }
    swap(&arr[i + 1], &arr[high]);
    return (i + 1);
}

void quickSort(Computer arr[], int low, int high){
    if (low < high){
        int pi = partition(arr, low, high);
        quickSort(arr, low, pi - 1);
        quickSort(arr, pi + 1, high);
    }
}
int afford(int budget, int price)
{
	if(budget - price >= 0) return 1;
	return 0; 
